const createIconGrid = (icons, size) => {
  const container = document.createElement('div');
  container.className = 'bsdex-icon-grid';

  Object.entries(icons).forEach(([name, svg]) => {
    const item = document.createElement('div');
    item.className = 'bsdex-icon-item';
    item.innerHTML = `
      <div class="bsdex-icon-preview">${svg}</div>
      <span class="bsdex-icon-name">${name}</span>
      <span class="bsdex-icon-size">${size}px</span>
    `;
    container.appendChild(item);
  });

  return container;
};

export const Icons24px = {
  render: () => {
    const wrapper = document.createElement('div');
    wrapper.innerHTML = '<h3 style="margin-bottom: 16px; font-size: 14px; font-weight: 600; color: #7c7c7c; text-transform: uppercase; letter-spacing: 1px;">24px Icons</h3>';
    wrapper.appendChild(createIconGrid(icons24, 24));
    return wrapper;
  },
};

