export const AllIcons = {
  render: () => {
    const wrapper = document.createElement('div');
    wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 32px;';

    const section24 = document.createElement('div');
    section24.innerHTML = '<h3 style="margin-bottom: 16px; font-size: 14px; font-weight: 600; color: #7c7c7c; text-transform: uppercase; letter-spacing: 1px;">24px Icons (' + Object.keys(icons24).length + ')</h3>';
    section24.appendChild(createIconGrid(icons24, 24));

    const section16 = document.createElement('div');
    section16.innerHTML = '<h3 style="margin-bottom: 16px; font-size: 14px; font-weight: 600; color: #7c7c7c; text-transform: uppercase; letter-spacing: 1px;">16px Icons (' + Object.keys(icons16).length + ')</h3>';
    section16.appendChild(createIconGrid(icons16, 16));

    wrapper.appendChild(section24);
    wrapper.appendChild(section16);
    return wrapper;
  },
};

