export const CurrencyIconsFull = {
  render: () => {
    const wrapper = document.createElement('div');
    wrapper.innerHTML = '<h3 style="margin-bottom: 16px; font-size: 14px; font-weight: 600; color: #7c7c7c; text-transform: uppercase; letter-spacing: 1px;">Currency Icons - Full Color (' + Object.keys(currenciesFull).length + ')</h3>';
    wrapper.appendChild(createIconGrid(currenciesFull, 24));
    return wrapper;
  },
};

